import{c as e,Q as o,j as r,m as n}from"./chunks/framework.D5MFXpji.js";const h=JSON.parse('{"title":"Environment","description":"","frontmatter":{"title":"Environment","order":6},"headers":[],"relativePath":"ko/environment/index.md","filePath":"ko/environment/index.md","lastUpdated":1781137916000}'),s={name:"ko/environment/index.md"};function a(i,t,l,c,p,d){return o(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="환경" tabindex="-1">환경 <a class="header-anchor" href="#환경" aria-label="Permalink to &quot;환경&quot;">​</a></h1><p>그림자가 적용되어 입체감이 형성된 공간에, 이제 무한한 배경과 실사 같은 빛 정보를 더할 차례입니다. RedGPU는 3D 씬의 현실감을 극대화하기 위해 다음과 같은 환경 구성 기능을 제공합니다.</p><ul><li><strong>스카이박스 (Skybox)</strong>: 씬의 무한한 배경을 표현</li><li><strong>이미지 기반 조명 (IBL)</strong>: 주변 환경의 이미지를 광원으로 이용한 물리 기반 반사 및 전역 조명</li><li><strong>스카이 대기 (SkyAtmosphere)</strong>: 실시간 물리 기반 대기 산란 시뮬레이션</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>화면의 최종 색감을 정교하게 조율하는 **톤 매핑 (Tone Mapping)**은 이후 포스트 이펙트(Post-effects) 섹션에서 자세히 다룹니다.</p></div><h2 id="주요-학습-내용" tabindex="-1">주요 학습 내용 <a class="header-anchor" href="#주요-학습-내용" aria-label="Permalink to &quot;주요 학습 내용&quot;">​</a></h2><ul><li><strong><a href="./skybox.html">스카이박스</a></strong> : 씬의 배경을 360도 텍스처로 채워 광활한 공간감을 제공합니다.</li><li><strong><a href="./ibl.html">IBL</a></strong> : 주위 환경의 빛 정보를 분석하여 객체에 사실적인 반사와 조명을 적용합니다.</li><li><strong><a href="./skyatmosphere.html">스카이 대기 (SkyAtmosphere)</a></strong> : 실시간 물리 기반 대기 산란 시뮬레이션을 통해 시시각각 변화하는 하늘과 대기 산란 효과를 씬에 부여합니다.</li></ul><div class="info custom-block"><p class="custom-block-title">[학습 가이드]</p><p>가장 먼저 공간의 배경을 정의하는 <strong>SkyBox</strong> 부터 시작하여, 그 배경이 물체에 실제 조명으로 작용하는 <strong>IBL</strong>, 그리고 실시간 대기 산란을 물리적으로 시뮬레이션하는 <strong>SkyAtmosphere</strong> 까지 순차적으로 알아보겠습니다.</p></div><hr><p><a href="./skybox.html">다음 단계: SkyBox 배우기</a></p>',9)])])}const g=e(s,[["render",a]]);export{h as __pageData,g as default};
